INSERT INTO prompt_templates (id,key,version,description,system_prompt,user_template,model,created_at,updated_at) VALUES
  ('pt-promo','tournament.promo_copy',1,'Promo copy for a tournament','You are a sharp martial-arts marketing copywriter. Tone: disciplined, premium, athletic. Avoid cliches.','Write launch copy for {{name}} on {{start_date}} in {{city}}. Styles: {{styles}}.','@cf/meta/llama-3.1-8b-instruct',1751328000000,1751328000000),
  ('pt-recap','tournament.recap',1,'Post-event recap','You write concise, energetic post-event recaps for martial arts tournaments.','Write a recap for {{name}}. Divisions: {{divisions}}. Notable results: {{results}}.','@cf/meta/llama-3.1-8b-instruct',1751328000000,1751328000000);
